import React,{useState} from 'react';

function Todo() {
    const [item,setItem]=useState()
  return (
    <div className="App">
     <>

    <h1 className='heading'>
        todo app
    </h1>
   
<input type="text" placeholder='add items' onChange={item} />
<button>add</button>
<ol>
    <li>
       {setItem}
    </li>
</ol>
      </>
    </div>
  );
}

export default Todo;
